const focusTechnicalBuilding = useCallback((buildingId) => {
  const id = String(buildingId || '').trim();
  if (!id) return;
  setMapView(MAP_VIEWS.TECHNICAL);
  setSelectedBuildingId(id);
  selectedBuildingIdRef.current = id;
  setIsTechnicalPanelOpen(true);
  setPopupMode('building');
  setFloorStats(null);

  const resolvedName = resolveBuildingNameFromInput(id);
  if (resolvedName) setSelectedBuilding(resolvedName);

  const map = mapRef.current;
  const features = Array.isArray(config?.buildings?.features) ? config.buildings.features : [];
  const feature =
    matchBuildingFeature(features, id) ||
    features.find((candidate) => String(candidate?.properties?.id || '').trim() === id) ||
    null;
  if (feature) selectedBuildingFeatureRef.current = feature;

  if (map && feature) {
    const featureId = String(feature?.properties?.id || id).trim() || id;
    try {
      if (previousSelectedBuildingId.current) {
        map.setFeatureState({ source: 'buildings', id: previousSelectedBuildingId.current }, { selected: false });
      }
      map.setFeatureState({ source: 'buildings', id: featureId }, { selected: true });
      previousSelectedBuildingId.current = featureId;
    } catch {}
    try {
      const bbox = turf.bbox(feature);
      if (Array.isArray(bbox) && bbox.length === 4 && bbox.every((value) => Number.isFinite(value))) {
        map.fitBounds(
          [[bbox[0], bbox[1]], [bbox[2], bbox[3]]],
          { padding: 70, duration: 550, maxZoom: 18.5 }
        );
      }
    } catch {}
  }

  showBuildingStats(id);
}, [config, showBuildingStats, resolveBuildingNameFromInput]);
const jumpToNextIncompleteTechnicalBuilding = useCallback(() => {
  const next = technicalProgressRows.find((row) => !row.isComplete) || technicalProgressRows[0] || null;
  if (!next) return;
  focusTechnicalBuilding(next.id);
}, [technicalProgressRows, focusTechnicalBuilding]);

const engagementRoomSentimentSummary = useMemo(() => {
  const empty = {
    matchPairs: [],
    legendItems: [],
    roomCount: 0,
    markerCount: 0
  };
  if (!engagementMode || !engagementRoomSentimentOn) return empty;
  if (!loadedSingleFloor || !isEngagementFloorScope) return empty;
  const map = mapRef.current;
  const src = map ? getGeojsonSource(map, FLOOR_SOURCE) : null;
  const data = src ? (src._data || src.serialize?.().data || null) : null;
  const ctxFc = currentFloorContextRef.current?.fc || null;
  const fc = toFeatureCollection(ctxFc || data);
  if (!fc?.features?.length) return empty;

  const roomFeatures = fc.features
    .filter((feature) => featureLooksLikeRoom(feature))
    .filter((feature) => {
      const geomType = String(feature?.geometry?.type || '');
      return geomType === 'Polygon' || geomType === 'MultiPolygon';
    })
    .map((feature) => {
      const props = feature.properties || {};
      const rawId = feature.id ?? props.RevitId ?? props.id;
      if (rawId == null) return null;
      const areaSf = resolvePatchedArea(props);
      return {
        feature,
        idRaw: rawId,
        idKey: String(rawId),
        areaSf: Number.isFinite(areaSf) ? areaSf : 0
      };
    })
    .filter(Boolean);
  if (!roomFeatures.length) return empty;

  const roomCounts = new Map();
  roomFeatures.forEach((room) => roomCounts.set(room.idKey, { counts: new Map(), total: 0 }));

  let matchedMarkers = 0;
  (scopedEngagementMarkers || [])
    .filter((marker) => Array.isArray(marker?.coordinates))
    .forEach((marker) => {
      const lng = Number(marker?.coordinates?.[0]);
      const lat = Number(marker?.coordinates?.[1]);
      if (!Number.isFinite(lng) || !Number.isFinite(lat)) return;
      const markerPoint = turf.point([lng, lat]);
      for (const room of roomFeatures) {
        let inRoom = false;
        try {
          inRoom = turf.booleanPointInPolygon(markerPoint, room.feature);
        } catch {
          inRoom = false;
        }
        if (!inRoom) continue;
        const category = getEngagementHeatCategory(marker?.type);
        const bucket = roomCounts.get(room.idKey);
        const prev = bucket.counts.get(category) || 0;
        bucket.counts.set(category, prev + 1);
        bucket.total += 1;
        matchedMarkers += 1;
        break;
      }
    });

  const categoryAgg = new Map();
  const matchPairs = [];
  let roomCount = 0;
  roomFeatures.forEach((room) => {
    const bucket = roomCounts.get(room.idKey);
    if (!bucket || !bucket.total) return;
    roomCount += 1;
    const sorted = Array.from(bucket.counts.entries()).sort((a, b) => {
      if ((b[1] || 0) !== (a[1] || 0)) return (b[1] || 0) - (a[1] || 0);
      const heatA = ENGAGEMENT_HEAT_CATEGORY_STYLE[a[0]]?.heatValue ?? 0;
      const heatB = ENGAGEMENT_HEAT_CATEGORY_STYLE[b[0]]?.heatValue ?? 0;
      return heatB - heatA;
    });
    const dominantCategory = sorted[0]?.[0] || 'comment';
    const dominantColor = ENGAGEMENT_HEAT_CATEGORY_STYLE[dominantCategory]?.color || '#9ca3af';
    matchPairs.push(room.idKey, dominantColor);

    const agg = categoryAgg.get(dominantCategory) || {
      category: dominantCategory,
      label: ENGAGEMENT_HEAT_CATEGORY_LABELS[dominantCategory] || dominantCategory,
      color: dominantColor,
      roomCount: 0,
      markerCount: 0,
      areaSf: 0
    };
    agg.roomCount += 1;
    agg.markerCount += bucket.total;
    agg.areaSf += room.areaSf || 0;
    categoryAgg.set(dominantCategory, agg);
  });

  const legendItems = Array.from(categoryAgg.values())
    .sort((a, b) => (b.roomCount || 0) - (a.roomCount || 0));
  return {
    matchPairs,
    legendItems,
    roomCount,
    markerCount: matchedMarkers
  };
}, [
  engagementMode,
  engagementRoomSentimentOn,
  loadedSingleFloor,
  isEngagementFloorScope,
  scopedEngagementMarkers,
  floorFeatureVersion
]);

useEffect(() => {
  if (!mapLoaded) return;
  const map = mapRef.current;
  if (!map || !map.getLayer(FLOOR_FILL_ID)) return;
  if (!engagementMode || !engagementRoomSentimentOn || !loadedSingleFloor || !isEngagementFloorScope) {
    clearEngagementRoomSentimentGradient(map);
    return;
  }
  if (engagementRoomFillStyle === 'solid') {
    clearEngagementRoomSentimentGradient(map);
    try {
      const fillExpr = engagementRoomSentimentSummary.matchPairs.length
        ? [
            'match',
            ['to-string', ['coalesce', ['id'], ['get', 'RevitId'], ['get', 'id']]],
            ...engagementRoomSentimentSummary.matchPairs,
            '#f8f7f2'
          ]
        : '#f8f7f2';
      map.setPaintProperty(FLOOR_FILL_ID, 'fill-color', fillExpr);
      map.setPaintProperty(FLOOR_FILL_ID, 'fill-opacity', 1);
    } catch {}
    return;
  }

  try {
    map.setPaintProperty(FLOOR_FILL_ID, 'fill-color', '#f8f7f2');
    map.setPaintProperty(FLOOR_FILL_ID, 'fill-opacity', 1);
  } catch {}

  try {
    const source = getGeojsonSource(map, FLOOR_SOURCE);
    const data = source ? (source._data || source.serialize?.().data || null) : null;
    const floorFc = toFeatureCollection(currentFloorContextRef.current?.fc || data);
    const colorByRoomId = new Map();
    const pairs = engagementRoomSentimentSummary.matchPairs || [];
    for (let i = 0; i < pairs.length; i += 2) {
      const id = pairs[i];
      const color = pairs[i + 1];
      if (id == null || !color) continue;
      colorByRoomId.set(String(id), color);
    }
    const gradientFc = buildRoomSentimentGradientFeatureCollection(floorFc, colorByRoomId);
    if (!gradientFc?.features?.length) {
      clearEngagementRoomSentimentGradient(map);
      return;
    }
    upsertGeoJsonSource(map, ENGAGEMENT_ROOM_SENTIMENT_GRADIENT_SOURCE_ID, gradientFc);

    const beforeId = map.getLayer(FLOOR_LINE_ID)
      ? FLOOR_LINE_ID
      : (map.getLayer(FLOOR_ROOM_LABEL_LAYER) ? FLOOR_ROOM_LABEL_LAYER : undefined);

    for (let band = 0; band < ENGAGEMENT_ROOM_SENTIMENT_BAND_COUNT; band += 1) {
      const layerId = `${ENGAGEMENT_ROOM_SENTIMENT_GRADIENT_LAYER_PREFIX}${band}`;
      const opacity = ENGAGEMENT_ROOM_SENTIMENT_BAND_OPACITY[band] ?? 0.5;
      if (!map.getLayer(layerId)) {
        map.addLayer(
          {
            id: layerId,
            type: 'fill',
            source: ENGAGEMENT_ROOM_SENTIMENT_GRADIENT_SOURCE_ID,
            filter: ['==', ['get', 'band'], band],
            paint: {
              'fill-color': ['get', 'color'],
              'fill-opacity': opacity
            }
          },
          beforeId
        );
      } else {
        try { map.setFilter(layerId, ['==', ['get', 'band'], band]); } catch {}
        try { map.setPaintProperty(layerId, 'fill-color', ['get', 'color']); } catch {}
        try { map.setPaintProperty(layerId, 'fill-opacity', opacity); } catch {}
      }
    }
    bringFloorRoomLabelsToFront(map);
  } catch {
    clearEngagementRoomSentimentGradient(map);
  }
}, [
  mapLoaded,
  engagementMode,
  engagementRoomSentimentOn,
  engagementRoomFillStyle,
  loadedSingleFloor,
  isEngagementFloorScope,
  engagementRoomSentimentSummary,
  floorFeatureVersion
]);

