                    borderColor: markerToolSelectedArchivedRows.length ? '#991b1b' : undefined,
                    color: markerToolSelectedArchivedRows.length ? '#fff' : undefined,
                    fontWeight: markerToolSelectedArchivedRows.length ? 700 : undefined
